query:
-- Step 1: Close all open positions
UPDATE paperPositions SET status='closed', closedAt=NOW() WHERE status='open';

-- Step 2: Clear all paper trades history
DELETE FROM paperTrades;

-- Step 3: Clear all equity snapshots
DELETE FROM paperEquitySnapshots;

-- Step 4: Reset ledger to clean $100,000
UPDATE paperLedger SET availableCash=100000, updatedAt=NOW() WHERE userId=1;

-- Step 5: Verify
SELECT availableCash, initialCapital FROM paperLedger WHERE userId=1;

